package main

import (
	"fmt"
	"net/http"
)

// Very small illustrative example: expose who the leader is
func main() {
	http.HandleFunc("/whoami", func(w http.ResponseWriter, r *http.Request) {
		// imagine 'isLeader' and 'leaderID' are provided by your Raft lib
		isLeader := false
		leaderID := "node-3"
		if isLeader {
			fmt.Fprintln(w, "I am leader")
		} else {
			fmt.Fprintf(w, "Leader=%s\n", leaderID)
		}
	})
	http.ListenAndServe(":8080", nil)
}
